if (! function_exists('crypto_price_history')) {
    function crypto_price_history($coin = null, $currency = null, $days = null, $sma_window = null, $timeout = null)
    {
            $coin = $coin ?? 'bitcoin';
            $currency = $currency ?? 'usd';
            $days = $days ?? 30;
            $sma_window = $sma_window ?? 7;
            $timeout = $timeout ?? 20;

            $timeout = max(5, min(30, (int)$timeout));
            $coin = trim(strtolower($coin));
            $currency = trim(strtolower($currency));
            $days = max(1, min(365, (int)$days));

            if (empty($coin)) $coin = 'bitcoin';

            // Helper: fetch JSON
            $fetch_json = function($url, $t) {
                $ctx = stream_context_create([
                    'http' => ['method' => 'GET', 'timeout' => $t, 'header' => "User-Agent: crypto_price_history/1.0\r\n", 'ignore_errors' => true],
                    'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                ]);
                $body = @file_get_contents($url, false, $ctx);
                if ($body === false) return ['error' => error_get_last()['message'] ?? 'fetch failed', 'success' => false];
                $status = 200;
                if (isset($http_response_header)) {
                    foreach ($http_response_header as $h) {
                        if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
                    }
                }
                if ($status === 429) return ['error' => 'Rate limited (429)', 'success' => false];
                if ($status === 404) return ['error' => 'Coin not found (404)', 'success' => false];
                if ($status >= 400) return ['error' => "HTTP $status", 'success' => false];
                $data = @json_decode($body, true);
                if ($data === null) return ['error' => 'Invalid JSON', 'success' => false];
                return ['data' => $data, 'status' => $status, 'success' => true];
            };

            // Fetch market chart data
            $url = "https://api.coingecko.com/api/v3/coins/{$coin}/market_chart?vs_currency={$currency}&days={$days}";
            $result = $fetch_json($url, $timeout);

            if (!$result['success']) {
                // Fallback: try the simple price endpoint for at least current price
                $simple_url = "https://api.coingecko.com/api/v3/simple/price?ids={$coin}&vs_currencies={$currency}&include_24hr_change=true";
                $simple = $fetch_json($simple_url, $timeout);
                if ($simple['success'] && isset($simple['data'][$coin])) {
                    $c = $simple['data'][$coin];
                    return [
                        'success' => true,
                        'coin' => $coin,
                        'currency' => strtoupper($currency),
                        'note' => 'Historical data unavailable, showing current price only.',
                        'current_price' => $c[$currency] ?? null,
                        'change_24h_percent' => $c[$currency . '_24h_change'] ?? null,
                        'data_points' => 0,
                        'trend' => 'minimal',
                    ];
                }
                return ['success' => false, 'error' => "CoinGecko API: " . $result['error'], 'coin' => $coin];
            }

            $data = $result['data'];
            $prices = $data['prices'] ?? [];
            $market_caps = $data['market_caps'] ?? [];
            $total_volumes = $data['total_volumes'] ?? [];

            if (empty($prices)) {
                return [
                    'success' => false,
                    'error' => "No price data returned for '$coin'.",
                    'coin' => $coin,
                ];
            }

            // Extract price series (timestamp, price)
            $price_series = [];
            foreach ($prices as $p) {
                $price_series[] = ['timestamp' => (int)($p[0] / 1000), 'price' => $p[1]];
            }

            $prices_only = array_map(function($p) { return $p['price']; }, $price_series);
            $timestamps = array_map(function($p) { return $p['timestamp']; }, $price_series);
            $n = count($prices_only);

            // Current stats
            $first_price = $prices_only[0];
            $last_price = $prices_only[$n - 1];
            $price_change = $last_price - $first_price;
            $price_change_percent = $first_price > 0 ? round(($price_change / $first_price) * 100, 2) : 0;

            // High / Low
            $high = max($prices_only);
            $low = min($prices_only);
            $high_at = $timestamps[array_search($high, $prices_only)];
            $low_at = $timestamps[array_search($low, $prices_only)];

            // Simple Moving Average
            $sma_values = [];
            $sma_window = max(2, min($n, (int)$sma_window));
            for ($i = 0; $i < $n; $i++) {
                if ($i < $sma_window - 1) {
                    $sma_values[] = null;
                } else {
                    $sum = 0;
                    for ($j = 0; $j < $sma_window; $j++) {
                        $sum += $prices_only[$i - $j];
                    }
                    $sma_values[] = $sum / $sma_window;
                }
            }
            $current_sma = $sma_values[$n - 1];

            // Volatility (standard deviation of daily returns)
            $daily_returns = [];
            for ($i = 1; $i < $n; $i++) {
                $prev = $prices_only[$i - 1];
                if ($prev > 0) {
                    $daily_returns[] = ($prices_only[$i] - $prev) / $prev;
                }
            }
            $return_count = count($daily_returns);
            $volatility = null;
            if ($return_count > 1) {
                $mean_return = array_sum($daily_returns) / $return_count;
                $variance = 0;
                foreach ($daily_returns as $r) {
                    $variance += ($r - $mean_return) ** 2;
                }
                $variance /= ($return_count - 1);
                $volatility = sqrt($variance) * 100; // as percentage
            }

            // Determine trend direction
            $recent = array_slice($prices_only, -min(5, $n));
            $trend = 'stable';
            if (count($recent) >= 2) {
                $first_recent = $recent[0];
                $last_recent = $recent[count($recent) - 1];
                $change = $last_recent - $first_recent;
                $change_pct = $first_recent > 0 ? ($change / $first_recent) * 100 : 0;
                if ($change_pct > 2) $trend = 'up';
                elseif ($change_pct < -2) $trend = 'down';
            }

            // Generate a compact ASCII sparkline (10 characters)
            $sparkline_chars = ['▁', '▂', '▃', '▄', '▅', '▆', '▇', '█'];
            $sparkline = '';
            if ($n > 1) {
                $sample_count = min(20, $n);
                $step = max(1, (int)($n / $sample_count));
                $sampled = [];
                for ($i = 0; $i < $n; $i += $step) {
                    $sampled[] = $prices_only[$i];
                }
                // Always include last point
                if (end($sampled) !== $prices_only[$n - 1]) $sampled[] = $prices_only[$n - 1];

                $s_min = min($sampled);
                $s_max = max($sampled);
                $s_range = $s_max - $s_min;
                foreach ($sampled as $s) {
                    if ($s_range > 0) {
                        $idx = (int)((($s - $s_min) / $s_range) * (count($sparkline_chars) - 1));
                    } else {
                        $idx = count($sparkline_chars) / 2;
                    }
                    $idx = max(0, min(count($sparkline_chars) - 1, $idx));
                    $sparkline .= $sparkline_chars[$idx];
                }
            }

            // Sampling for timeseries (for large datasets, return every Nth point)
            $max_return_points = 100;
            $series_step = max(1, (int)($n / $max_return_points));
            $return_series = [];
            for ($i = 0; $i < $n; $i += $series_step) {
                $return_series[] = [
                    'timestamp' => $timestamps[$i],
                    'date' => gmdate('Y-m-d', $timestamps[$i]),
                    'price' => round($prices_only[$i], 6),
                    'sma' => $sma_values[$i] !== null ? round($sma_values[$i], 6) : null,
                ];
            }
            // Always include last point
            $last_idx = $n - 1;
            if (count($return_series) === 0 || end($return_series)['timestamp'] !== $timestamps[$last_idx]) {
                $return_series[] = [
                    'timestamp' => $timestamps[$last_idx],
                    'date' => gmdate('Y-m-d', $timestamps[$last_idx]),
                    'price' => round($prices_only[$last_idx], 6),
                    'sma' => $sma_values[$last_idx] !== null ? round($sma_values[$last_idx], 6) : null,
                ];
            }

            // Current vs SMA
            $above_sma = null;
            if ($current_sma !== null && $current_sma > 0) {
                $above_sma = round(($last_price - $current_sma) / $current_sma * 100, 2);
            }

            return [
                'success' => true,
                'coin' => $coin,
                'currency' => strtoupper($currency),
                'period_days' => $days,
                'data_points' => $n,
                'current_price' => round($last_price, 6),
                'price_change' => [
                    'absolute' => round($price_change, 6),
                    'percent' => $price_change_percent,
                    'from' => round($first_price, 6),
                    'to' => round($last_price, 6),
                ],
                'high_low' => [
                    'high' => round($high, 6),
                    'high_date' => gmdate('Y-m-d H:i:s', $high_at),
                    'low' => round($low, 6),
                    'low_date' => gmdate('Y-m-d H:i:s', $low_at),
                ],
                'volatility' => [
                    'daily_stddev_percent' => $volatility !== null ? round($volatility, 2) : null,
                    'classification' => $volatility !== null ? 
                        ($volatility < 2 ? 'Low' : ($volatility < 5 ? 'Moderate' : ($volatility < 10 ? 'High' : 'Extreme'))) 
                        : null,
                ],
                'moving_average' => [
                    'sma_window' => $sma_window,
                    'current_sma' => $current_sma !== null ? round($current_sma, 6) : null,
                    'price_vs_sma_percent' => $above_sma,
                    'above_sma' => $above_sma !== null ? ($above_sma > 0 ? true : false) : null,
                ],
                'trend' => [
                    'direction' => $trend,
                    'sparkline' => $sparkline,
                ],
                'series' => $return_series,
                'volume_data' => !empty($total_volumes) ? [
                    'current' => round(end($total_volumes)[1], 2),
                    'highest' => round(max(array_column($total_volumes, 1)), 2),
                ] : null,
            ];
    }
}
